import style from "./index.module.scss"
import template from './index.html'
import {
  scaleBand,
  scaleLinear,
  axisBottom,
  select,
  max,
  axisLeft,
} from 'd3'
import { USDollarFormat, handleTooltip } from "../../utils/util"

export default class BarChart extends HTMLElement {
  // set active(value: string) {
  //   this.setAttribute("active", value)
  // }
  // get active(): boolean {
  //   const value = this.getAttribute("active")
  //   return value === "true" ? true : false
  // }
  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    const sheet = new CSSStyleSheet();
    sheet.replaceSync(style);
    shadowRoot.adoptedStyleSheets = [sheet];
    shadowRoot.innerHTML = template
  }
  static get observedAttributes() {
    return ["data"];
  }
  attributeChangedCallback(name, oldValue, newValue) {
    this.render()
  }

  willLoad = () => {
  }
  connectedCallback() {
    this.classList.add("hydrated")
    handleTooltip(this)
    setTimeout(() => {
      this.willLoad()
      this.render()
      window.addEventListener("resize", e => {
        this.render()
      })
    })
  }
  disconnectedCallback() {
  }


  render = () => {
    const parent = this.parentElement
    if (!parent) return
    if (!this.shadowRoot) return
    const { width: rectW } = parent.getBoundingClientRect()
    this.rootEle = this.shadowRoot?.querySelector(".root")
    if (!this.rootEle || rectW === 0) return
    this.rootEle.innerHTML = ""
    const parentPadding = 40
    // set the dimensions and margins of the graph
    const margin = { top: 20, right: 20, bottom: 30, left: 40 }
    const width = rectW - margin.left - margin.right - parentPadding
    const height = 400 - margin.top - margin.bottom;

    // set the ranges
    const x = scaleBand()
      .range([0, width])
      .padding(0.1);
    const y = scaleLinear()
      .range([height, 0]);

    const yAxisLeft = axisLeft(y)
      .tickSize(0)
      .tickPadding(10)
      .ticks(2)
      // .tickValues([0, yAxisLeftMax])
      .tickFormat(value => {
        return USDollarFormat(value, { notation: 'compact' })
      });

    const xAxis = axisBottom(x).tickSize(0).offset(0).tickPadding(10).tickSizeOuter(0);

    // append the svg object to the body of the page
    // append a 'group' element to 'svg'
    // moves the 'group' element to the top left margin
    const svg = select(this.rootEle).append("svg")
      .attr("width", width + margin.left + margin.right)
      .attr("height", height + margin.top + margin.bottom)
      .append("g")
      .attr("transform",
        "translate(" + margin.left + "," + margin.top + ")");

    const data = [
      { month: 3, view: 20000 },
      { month: 6, view: 10000 },
      { month: 9, view: 13000 },
      { month: 12, view: 13000 },
      { month: 15, view: 8000 },
      { month: 18, view: 4000 },
      { month: 21, view: 16000 },
      { month: 24, view: 4000 },
      { month: 27, view: 8000 },
      { month: 31, view: 8000 },
    ]
    // get the data


    // format the data
    data.forEach((d) => {
      d.view = +d.view;
    });

    // Scale the range of the data in the domains
    x.domain(data.map((d) => d.month));
    y.domain([0, max(data, d => d.view)]);

        // y grid line
    // gridlines in y axis function
    function make_y_gridlines() {
      return axisLeft(y)
        .ticks(5)
    }
    svg.append("g")
      .attr("class", "y grid")
      .call(make_y_gridlines()
        .tickSize(-width)
        .tickFormat("")
      )
      .call(g => g.selectAll(".tick line")
                .attr("class", "y-axis-grid")
                .attr("stroke-dasharray", "5")
                .attr("stroke", "var(--text-quaternary)"))
      .call(d => d.select(".domain").remove())

    function topRoundedColumn(data, width) {
      const radius = width / 1.8
      const barWitdh = 10
      const heightBeforeArc = height - y(data.view) - radius
      return `M${x(data.month) + x.bandwidth() / 2 - barWitdh / 2},${y(data.view) + radius} ` + // Mx,y Move the pen to(x, y)
        `a ${radius},${radius} 0 0 1 ${radius},-${radius} ` + // arc
        `h${barWitdh - 2 * radius}` +
        `a ${radius},${radius} 0 0 1 ${radius},${radius} ` +
        `v${heightBeforeArc} ` +
        `h${-barWitdh}` +
        `z` // close shape

      // const rx = 10
      // const ry = 10
      // return `
      //   M${x(data.month)},${y(data.view) + ry}
      //   a${rx},${ry} 0 0 1 ${rx},${-ry}
      //   h${x.bandwidth() - 2 * rx}
      //   a${rx},${ry} 0 0 1 ${rx},${ry}
      //   v${height - y(data.view) - ry}
      //   h${-(x.bandwidth())}Z
      // `
    }
    // append the rectangles for the bar chart
    // svg.selectAll(".bar")
    //   .data(data)
    //   .enter().append("rect")
    //   .attr("class", "bar")
    //   .attr("x", d => x(d.month))
    //   .attr("width", 10)
    //   .attr("y", d => y(d.view))
    //   .style("fill", d => "var(--color-primary)")
    //   .attr("height", d => height - y(d.view));

    // path approach
    svg.selectAll(".bar")
      .data(data)
      .enter().append("path")
      .attr("class", "bar")
      .style("cursor", "pointer")
      .attr("width", 10)
      .attr("d", d => topRoundedColumn(d, 10))
      .style("fill", d => "var(--color-primary)")
      .on('mouseover', (e, d) => {
        this.tooltip.style.display = "flex"
        select(this.tooltip)
          .transition()
          .duration(200)
          .style('opacity', 1)
        const dot = this.tooltip.querySelector(".dot")
        dot.style.background = "#555ed1"
        const text = this.tooltip.querySelector(".text")
        text.innerHTML = `${d.month} days - ${USDollarFormat(d.view, { notation: 'compact' })} views`
      })
      .on('mouseout', (e) => {
        select(this.tooltip).style('opacity', 0)
        this.tooltip.style.display = "none"
      })
      .on('mousemove', e => {
        select(this.tooltip)
          .style('left', (e.clientX + 10) + 'px')
          .style('top', (e.clientY + 10) + 'px')
      })

    // add the x Axis
    svg.append("g")
      .attr("class", "x axis")
      .attr("transform", "translate(0," + height + ")")
      .call(xAxis)
      .call(d => d.select(".domain").remove())

    // add the y Axis
    svg.append("g")
      .attr("class", "y axis")
      .call(yAxisLeft)
      .call(d => d.select(".domain").remove())


    // x grid line
    // function make_x_gridlines() {
    //   return axisBottom(x)
    //     .ticks(5)
    // }
    // svg.append("g")
    //   .attr("class", "grid")
    //   .attr("transform", "translate(0," + height + ")")
    //   .call(make_x_gridlines()
    //     .tickSize(-height)
    //     .tickFormat("")
    //   )





  }
}
